const { spawn } = require('child_process');

return new Promise((resolve) => {
  // First, try to diagnose the environment
  const diagProcess = spawn('which', ['python3']);
  let pythonPath = '';
  let diagError = '';

  diagProcess.stdout.on('data', (data) => {
    pythonPath += data.toString().trim();
  });

  diagProcess.stderr.on('data', (data) => {
    diagError += data.toString();
  });

  diagProcess.on('close', () => {
    const scriptPath = '/Users/hieudt/vps-automation-vhck/scripts/fetch_vsd.py';
    const pythonExe = pythonPath || 'python3';

    const pythonProcess = spawn(pythonExe, [scriptPath]);
    let output = '';
    let errorOutput = '';

    const timeout = setTimeout(() => {
      pythonProcess.kill();
      resolve([{
        json: {
          error: 'Script execution timeout (300s exceeded)',
          status: 'timeout'
        }
      }]);
    }, 300000);

    pythonProcess.stdout.on('data', (data) => {
      output += data.toString();
    });

    pythonProcess.stderr.on('data', (data) => {
      errorOutput += data.toString();
    });

    pythonProcess.on('close', (code) => {
      clearTimeout(timeout);
      if (code !== 0) {
        resolve([{
          json: {
            error: `Script exited with code ${code}`,
            stderr: errorOutput,
            pythonPath: pythonPath,
            scriptPath: scriptPath,
            status: 'error'
          }
        }]);
        return;
      }

      try {
        const vsdData = JSON.parse(output);
        resolve([{ json: { data: vsdData } }]);
      } catch (e) {
        resolve([{
          json: {
            error: 'Failed to parse JSON output',
            message: e.message,
            status: 'error'
          }
        }]);
      }
    });

    pythonProcess.on('error', (error) => {
      clearTimeout(timeout);
      resolve([{
        json: {
          error: error.message,
          pythonPath: pythonPath,
          status: 'error'
        }
      }]);
    });
  });
});

// Combine results from VSD only
const vsdOutput = $node["Fetch VSD (Tin Tuc)"].json;
const vsdResult = vsdOutput.data || vsdOutput;

const allRecords = [];
const recordMap = {};

// Add VSD records
if (vsdResult?.data && Array.isArray(vsdResult.data)) {
  vsdResult.data.forEach(record => {
    allRecords.push({ ...record, source: 'VSD' });
    recordMap[record.code] = record;
  });
}

return [{
