const fs = require('fs');
const path = '/Users/hieudt/vps-automation-vhck/data/result.md';
const input = $input.first().json;
const records = input.records;
const summary = input.summary;

const timestamp = new Date().toLocaleString('vi-VN');
const newRecords = summary.vsd || records.length;
const totalRecords = records.length;
const pendingCount = records.filter(r => r.confirmation_status === 'awaiting_review').length;

// Tạo section cập nhật mới (hiển thị lên trên)
const updateSection = `## 📊 Thống Kê\n\n- **Cập nhật lúc:** ${timestamp}\n- **Tổng bản ghi (duy nhất):** ${totalRecords}\n  - VSD: ${summary.vsd}\n- **Chờ xác nhận:** ${pendingCount}\n`;

try {
  let existingContent = '';
  let history = '';

  // Đọc file cũ nếu tồn tại
  if (fs.existsSync(path)) {
    existingContent = fs.readFileSync(path, 'utf-8');
  }

  // Trích history content từ file cũ (nội dung sau separator ---)
  let historyContent = '';
  if (existingContent && existingContent.includes('---')) {
    const separatorIndex = existingContent.indexOf('---');
    historyContent = existingContent.substring(separatorIndex + 3).trim();
  } else if (existingContent) {
    // Nếu không có separator, extract nội dung cũ làm history (bỏ header)
    const headerLine = '# Kết Quả Thu Thập Thông Tin Quyền Chứng Khoán';
    const headerStart = existingContent.indexOf(headerLine);
    if (headerStart !== -1) {
      const headerEnd = headerStart + headerLine.length;
      let content = existingContent.substring(headerEnd);
      // Bỏ qua khoảng trắng đầu
      content = content.replace(/^\s+/, '');
      if (content) {
        historyContent = content;
      }
    }
  }

  // Xây dựng nội dung file mới: header + update mới + separator + history cũ
  const headerLine = '# Kết Quả Thu Thập Thông Tin Quyền Chứng Khoán';
  let newContent = headerLine + '\n\n' + updateSection + '\n---';

  // Thêm history content nếu có
  if (historyContent) {
    newContent += '\n\n' + historyContent;
  }

  // Ghi file
  fs.writeFileSync(path, newContent, 'utf-8');

  return [{
    json: {
      status: 'success',
      message: 'Updated result.md with new data and preserved history',
      file: path,
      timestamp: new Date().toISOString(),
      new_records: newRecords,
      total_records: totalRecords,
      pending_count: pendingCount
    }
  }];
} catch (error) {
  return [{
    json: {
      status: 'error',
      message: error.message,
      file: path
    }
  }];
}

return [{
  json: {
    status: 'success',
    message: 'Workflow hoàn thành!',
    timestamp: new Date().toISOString(),
    next_step: 'Xem result.md để review dữ liệu'
  }
}];

const { spawn } = require('child_process');

return new Promise((resolve) => {
  // Start HTTP server if not running
  const checkCmd = spawn('lsof', ['-i', ':8000']);

  checkCmd.on('close', (code) => {
    if (code === 0) {
      // Server already running
      resolve([{
        json: {
          status: 'success',
          message: 'HTTP server already running',
          url: 'http://localhost:8000/web/vps_automation_vhck.html'
        }
      }]);
    } else {
      // Start server
      const startCmd = spawn('bash', ['-c', 'cd /Users/hieudt/vps-automation-vhck && python3 -m http.server 8000 > /tmp/http_server.log 2>&1 &']);

      startCmd.on('close', () => {
        setTimeout(() => {
          resolve([{
            json: {
              status: 'success',
              message: 'HTTP server started',
              url: 'http://localhost:8000/web/vps_automation_vhck.html',
              timestamp: new Date().toISOString()
            }
          }]);
        }, 2000);
      });
    }
  });
});
